import{_ as e,o as t,c as r,ag as l}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"よくある質問 (FAQ)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),i={name:"guide/faq.md"};function o(d,a,h,n,c,s){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="よくある質問-faq" tabindex="-1">よくある質問 (FAQ) <a class="header-anchor" href="#よくある質問-faq" aria-label="Permalink to &quot;よくある質問 (FAQ)&quot;">​</a></h1><hr><h2 id="アップロード・ファイル関連" tabindex="-1">アップロード・ファイル関連 <a class="header-anchor" href="#アップロード・ファイル関連" aria-label="Permalink to &quot;アップロード・ファイル関連&quot;">​</a></h2><h3 id="q-どのファイル形式に対応していますか" tabindex="-1">Q: どのファイル形式に対応していますか？ <a class="header-anchor" href="#q-どのファイル形式に対応していますか" aria-label="Permalink to &quot;Q: どのファイル形式に対応していますか？&quot;">​</a></h3><p><strong>Excel アップロード:</strong> <code>.xlsx</code>（Excel 2007 以降）に対応しています。<code>.xls</code>（Excel 97-2003）は非対応です。</p><p><strong>XML インポート:</strong> ConMas i-Reporter Designer で書き出した <code>.xml</code> ファイルに対応しています。</p><h3 id="q-ファイルサイズの制限はありますか" tabindex="-1">Q: ファイルサイズの制限はありますか？ <a class="header-anchor" href="#q-ファイルサイズの制限はありますか" aria-label="Permalink to &quot;Q: ファイルサイズの制限はありますか？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ファイル種別</th><th>上限</th></tr></thead><tbody><tr><td>Excel (.xlsx)</td><td>10MB</td></tr><tr><td>XML (.xml)</td><td>50MB</td></tr></tbody></table><h3 id="q-複数シートの-excel-に対応していますか" tabindex="-1">Q: 複数シートの Excel に対応していますか？ <a class="header-anchor" href="#q-複数シートの-excel-に対応していますか" aria-label="Permalink to &quot;Q: 複数シートの Excel に対応していますか？&quot;">​</a></h3><p>はい。プレビュー画面でシートタブを切り替えられます。AI 解析は表示中のシートに対して実行されます。</p><hr><h2 id="ai-解析関連" tabindex="-1">AI 解析関連 <a class="header-anchor" href="#ai-解析関連" aria-label="Permalink to &quot;AI 解析関連&quot;">​</a></h2><h3 id="q-ai-解析にはどのくらい時間がかかりますか" tabindex="-1">Q: AI 解析にはどのくらい時間がかかりますか？ <a class="header-anchor" href="#q-ai-解析にはどのくらい時間がかかりますか" aria-label="Permalink to &quot;Q: AI 解析にはどのくらい時間がかかりますか？&quot;">​</a></h3><p>通常 <strong>10〜30 秒</strong> です。セル数が多い帳票や複雑なレイアウトの場合はもう少し時間がかかることがあります。</p><h3 id="q-ai-が検出できるクラスタータイプは" tabindex="-1">Q: AI が検出できるクラスタータイプは？ <a class="header-anchor" href="#q-ai-が検出できるクラスタータイプは" aria-label="Permalink to &quot;Q: AI が検出できるクラスタータイプは？&quot;">​</a></h3><p>現在 AI が自動検出対象としているのは以下の 10 タイプです:</p><p>KeyboardText, FixedText, Date, Time, InputNumeric, Calculate, Select, Check, Image, Handwriting</p><p>全 38 タイプの詳細は <a href="/reference/cluster-types.html">クラスタータイプ一覧</a> を参照してください。AI 未対応のタイプは、クラスターエディタの作成モードで手動追加できます。</p><h3 id="q-ai-の解析精度を上げるにはどうすればいいですか" tabindex="-1">Q: AI の解析精度を上げるにはどうすればいいですか？ <a class="header-anchor" href="#q-ai-の解析精度を上げるにはどうすればいいですか" aria-label="Permalink to &quot;Q: AI の解析精度を上げるにはどうすればいいですか？&quot;">​</a></h3><ul><li><strong>用紙サイズと向き</strong> を正しく設定してからAI解析を実行してください</li><li><strong>セルの結合</strong> が適切に設定されている Excel のほうが精度が高くなります</li><li><strong>データバリデーション</strong>（ドロップダウンリスト）が設定されていると、Select タイプの検出精度が向上します</li><li><strong>数式セル</strong> があると Calculate タイプが自動検出されます</li></ul><h3 id="q-ai-が検出しなかった項目を追加するには" tabindex="-1">Q: AI が検出しなかった項目を追加するには？ <a class="header-anchor" href="#q-ai-が検出しなかった項目を追加するには" aria-label="Permalink to &quot;Q: AI が検出しなかった項目を追加するには？&quot;">​</a></h3><p>クラスターエディタの <strong>作成モード</strong> (<code>N</code> キー) に切り替えて、プレビュー上でドラッグして矩形を描画します。詳しくは <a href="/guide/cluster-editor.html#作成モード">クラスターエディタ &gt; 作成モード</a> を参照してください。</p><hr><h2 id="クラスターエディタ関連" tabindex="-1">クラスターエディタ関連 <a class="header-anchor" href="#クラスターエディタ関連" aria-label="Permalink to &quot;クラスターエディタ関連&quot;">​</a></h2><h3 id="q-クラスターの位置がずれている場合は" tabindex="-1">Q: クラスターの位置がずれている場合は？ <a class="header-anchor" href="#q-クラスターの位置がずれている場合は" aria-label="Permalink to &quot;Q: クラスターの位置がずれている場合は？&quot;">​</a></h3><p>以下の方法で調整できます:</p><ol><li><strong>ドラッグ移動</strong> — クラスターを直接ドラッグ</li><li><strong>キーボードナッジ</strong> — 矢印キーで 1px 単位の微調整（Shift + 矢印で 10px）</li><li><strong>ツールバーのナッジボタン</strong> — 十字矢印ボタンで移動</li></ol><h3 id="q-複数のクラスターを一度に移動するには" tabindex="-1">Q: 複数のクラスターを一度に移動するには？ <a class="header-anchor" href="#q-複数のクラスターを一度に移動するには" aria-label="Permalink to &quot;Q: 複数のクラスターを一度に移動するには？&quot;">​</a></h3><ol><li><code>Shift</code> + クリックまたは <code>Ctrl</code> + クリックで複数選択</li><li>または背景をドラッグしてラバーバンド選択</li><li>バウンディングボックス（破線枠）をドラッグで一括移動</li></ol><h3 id="q-クラスターのタイプを変更するには" tabindex="-1">Q: クラスターのタイプを変更するには？ <a class="header-anchor" href="#q-クラスターのタイプを変更するには" aria-label="Permalink to &quot;Q: クラスターのタイプを変更するには？&quot;">​</a></h3><p>クラスターを選択すると右側のプロパティパネルが表示されます。「タイプ」のドロップダウンから変更できます。タイプを変更するとパラメータがそのタイプのデフォルト値にリセットされます。</p><h3 id="q-信頼度-confidence-とは何ですか" tabindex="-1">Q: 信頼度（Confidence）とは何ですか？ <a class="header-anchor" href="#q-信頼度-confidence-とは何ですか" aria-label="Permalink to &quot;Q: 信頼度（Confidence）とは何ですか？&quot;">​</a></h3><p>AI がそのクラスターの検出結果にどれだけ確信を持っているかを 0〜1 の数値で表したものです。</p><table tabindex="0"><thead><tr><th>範囲</th><th>意味</th><th>推奨アクション</th></tr></thead><tbody><tr><td>0.95</td><td>非常に高い</td><td>そのまま使用可能</td></tr><tr><td>0.85〜0.95</td><td>高い</td><td>軽く確認</td></tr><tr><td>0.70〜0.85</td><td>中程度</td><td>タイプとパラメータを確認</td></tr><tr><td>0.50〜0.70</td><td>低い</td><td>要確認・修正</td></tr></tbody></table><p>ツールバーのフィルターで信頼度別に表示を絞り込めます。</p><hr><h2 id="xml-出力関連" tabindex="-1">XML 出力関連 <a class="header-anchor" href="#xml-出力関連" aria-label="Permalink to &quot;XML 出力関連&quot;">​</a></h2><h3 id="q-生成された-xml-はどこで使えますか" tabindex="-1">Q: 生成された XML はどこで使えますか？ <a class="header-anchor" href="#q-生成された-xml-はどこで使えますか" aria-label="Permalink to &quot;Q: 生成された XML はどこで使えますか？&quot;">​</a></h3><p><strong>ConMas i-Reporter</strong> にそのままインポートできます。Designer でテンプレートとして読み込んでください。</p><h3 id="q-xml-を生成した後に修正したい場合は" tabindex="-1">Q: XML を生成した後に修正したい場合は？ <a class="header-anchor" href="#q-xml-を生成した後に修正したい場合は" aria-label="Permalink to &quot;Q: XML を生成した後に修正したい場合は？&quot;">​</a></h3><p>2つの方法があります:</p><ol><li><strong>ブラウザ上で続行</strong> — エディタに戻って修正し、再度 XML を生成</li><li><strong>XML を再インポート</strong> — ダウンロードした XML をもう一度アップロードして編集を再開（<a href="/guide/xml-import.html">XML インポート</a> 参照）</li></ol><hr><h2 id="環境・セットアップ関連" tabindex="-1">環境・セットアップ関連 <a class="header-anchor" href="#環境・セットアップ関連" aria-label="Permalink to &quot;環境・セットアップ関連&quot;">​</a></h2><h3 id="q-openai-api-key-はどこで取得できますか" tabindex="-1">Q: OpenAI API Key はどこで取得できますか？ <a class="header-anchor" href="#q-openai-api-key-はどこで取得できますか" aria-label="Permalink to &quot;Q: OpenAI API Key はどこで取得できますか？&quot;">​</a></h3><p><a href="https://platform.openai.com/" target="_blank" rel="noreferrer">OpenAI Platform</a> でアカウントを作成し、API Keys ページからキーを発行してください。GPT-5.1 対応のキーが必要です。</p><h3 id="q-api-の利用料金は" tabindex="-1">Q: API の利用料金は？ <a class="header-anchor" href="#q-api-の利用料金は" aria-label="Permalink to &quot;Q: API の利用料金は？&quot;">​</a></h3><p>OpenAI の従量課金が適用されます。1 帳票あたりの解析コストは帳票のセル数によりますが、通常は数円〜数十円程度です。</p><h3 id="q-ブラウザの推奨環境は" tabindex="-1">Q: ブラウザの推奨環境は？ <a class="header-anchor" href="#q-ブラウザの推奨環境は" aria-label="Permalink to &quot;Q: ブラウザの推奨環境は？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ブラウザ</th><th>対応</th></tr></thead><tbody><tr><td>Chrome (最新版)</td><td>推奨</td></tr><tr><td>Edge (最新版)</td><td>推奨</td></tr><tr><td>Firefox (最新版)</td><td>対応</td></tr><tr><td>Safari</td><td>未検証</td></tr></tbody></table><hr><h2 id="トラブルシューティング" tabindex="-1">トラブルシューティング <a class="header-anchor" href="#トラブルシューティング" aria-label="Permalink to &quot;トラブルシューティング&quot;">​</a></h2><h3 id="excel-のアップロードが失敗する" tabindex="-1">Excel のアップロードが失敗する <a class="header-anchor" href="#excel-のアップロードが失敗する" aria-label="Permalink to &quot;Excel のアップロードが失敗する&quot;">​</a></h3><ul><li>ファイルサイズが <strong>10MB 以下</strong> か確認してください</li><li><code>.xlsx</code> 形式であることを確認してください（<code>.xls</code> は非対応）</li><li>ファイルが破損していないか、Excel で正常に開けるか確認してください</li></ul><h3 id="ai-解析がエラーになる" tabindex="-1">AI 解析がエラーになる <a class="header-anchor" href="#ai-解析がエラーになる" aria-label="Permalink to &quot;AI 解析がエラーになる&quot;">​</a></h3><ul><li><code>.env.local</code> に <code>OPENAI_API_KEY</code> が正しく設定されているか確認してください</li><li>API キーの利用制限（Rate Limit）に達していないか確認してください</li><li>ネットワーク接続を確認してください</li></ul><h3 id="クラスターが表示されない" tabindex="-1">クラスターが表示されない <a class="header-anchor" href="#クラスターが表示されない" aria-label="Permalink to &quot;クラスターが表示されない&quot;">​</a></h3><ul><li>ツールバーのフィルターが有効になっていないか確認してください</li><li>タイプフィルターや信頼度フィルターをリセットしてみてください</li><li>ズームレベルを調整して、クラスターが画面外に出ていないか確認してください</li></ul><h3 id="xml-のインポートが失敗する" tabindex="-1">XML のインポートが失敗する <a class="header-anchor" href="#xml-のインポートが失敗する" aria-label="Permalink to &quot;XML のインポートが失敗する&quot;">​</a></h3><ul><li>ConMas i-Reporter 形式の XML であることを確認してください</li><li>ファイルサイズが <strong>50MB 以下</strong> か確認してください</li><li>XML が破損していないか、テキストエディタで開いて構造を確認してください</li></ul>',60)])])}const x=e(i,[["render",o]]);export{u as __pageData,x as default};
